/**
 * @summary List required document types for a dealer
 */
export const getListDocTypesUrl = (params: ListDocTypesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/doc-types?${stringifiedParams}`
    : `/api/doc-types`;
};

export const listDocTypes = async (
  params: ListDocTypesParams,
  options?: RequestInit,
): Promise<DocType[]> => {
  return customFetch<DocType[]>(getListDocTypesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListDocTypesQueryKey = (params?: ListDocTypesParams) => {
  return [`/api/doc-types`, ...(params ? [params] : [])] as const;
};

export const getListDocTypesQueryOptions = <
  TData = Awaited<ReturnType<typeof listDocTypes>>,
  TError = ErrorType<unknown>,
>(
  params: ListDocTypesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listDocTypes>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListDocTypesQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listDocTypes>>> = ({
    signal,
  }) => listDocTypes(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listDocTypes>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListDocTypesQueryResult = NonNullable<
  Awaited<ReturnType<typeof listDocTypes>>
>;
export type ListDocTypesQueryError = ErrorType<unknown>;

/**
 * @summary List required document types for a dealer
 */

export function useListDocTypes<
  TData = Awaited<ReturnType<typeof listDocTypes>>,
  TError = ErrorType<unknown>,
>(
  params: ListDocTypesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listDocTypes>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListDocTypesQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

